import json
from datetime import datetime, timezone
now = datetime.fromisoformat('2026-04-15T22:06:00+00:00')
with open('_tmp_live_tasks.json', encoding='utf-8') as f:
    data=json.load(f)

def rich(rt):
    return ''.join(x.get('plain_text','') for x in rt or []).strip()

def plain(prop):
    t=prop.get('type')
    if t=='title': return rich(prop.get('title'))
    if t=='rich_text': return rich(prop.get('rich_text'))
    if t=='status': return (prop.get('status') or {}).get('name')
    if t=='select': return (prop.get('select') or {}).get('name')
    if t=='checkbox': return prop.get('checkbox')
    if t=='date': return (prop.get('date') or {}).get('start')
    return None
rows=[]
for page in data['results']:
    props={k:plain(v) for k,v in page['properties'].items()}
    rows.append({
        'title': props.get('Task name'),
        'owner': props.get('Owner'),
        'status': props.get('Status'),
        'area': props.get('Area'),
        'needs_gustavo': props.get('Needs Gustavo'),
        'next_check': props.get('Next check'),
        'next_step': props.get('Next step'),
        'edited': page.get('last_edited_time'),
        'notes': props.get('Notes'),
    })

active=[r for r in rows if r['status'] not in ('Done', None)]
print('ACTIVE', len(active))
for r in active:
    dt=datetime.fromisoformat(r['edited'].replace('Z','+00:00'))
    age=(now-dt).days
    print(age, json.dumps(r, ensure_ascii=False))

print('\nNO OWNER >2d:')
for r in active:
    if not (r['owner'] or '').strip():
        dt=datetime.fromisoformat(r['edited'].replace('Z','+00:00'))
        age=(now-dt).days
        if age>2:
            print(age, r['title'], r['status'], '| next:', r['next_step'])
